<?php

namespace App\Http\Controllers;

use App\Models\Roombook;
use Illuminate\Http\Request;
use Illuminate\Support\Carbon;

class HomeController extends Controller
{
    /** Public landing page for logged-in users (was home.php). */
    public function index()
    {
        return view('home', ['countries' => $this->countries()]);
    }

    /** Handle the reservation form on the home page. */
    public function book(Request $request)
    {
        $name = $request->input('Name');
        $email = $request->input('Email');
        $country = $request->input('Country');

        if ($name == '' || $email == '' || $country == '') {
            return back()->with('error', 'Fill the proper details');
        }

        $cin = $request->input('cin');
        $cout = $request->input('cout');

        Roombook::create([
            'Name' => $name,
            'Email' => $email,
            'Country' => $country,
            'Phone' => $request->input('Phone'),
            'RoomType' => $request->input('RoomType'),
            'Bed' => $request->input('Bed'),
            'NoofRoom' => $request->input('NoofRoom'),
            'Meal' => $request->input('Meal'),
            'cin' => $cin,
            'cout' => $cout,
            'stat' => 'NotConfirm',
            'nodays' => $this->dayDiff($cin, $cout),
        ]);

        return back()->with('success', 'Reservation successful');
    }

    /** MySQL datediff(cout, cin) equivalent. */
    public static function dayDiff($cin, $cout): int
    {
        if (! $cin || ! $cout) {
            return 0;
        }

        return (int) Carbon::parse($cin)->diffInDays(Carbon::parse($cout));
    }

